// Gunny Nutrition Reference v1.0 — 293 entries across 13 categories.
//
// Sources: USDA FoodData Central (whole foods), official chain
// nutrition guides (fast food / restaurants), manufacturer labels
// (branded items / supplements), ISSN position stands + NIH ODS
// fact sheets (supplement effectiveness context). No fabricated data.
//
// Schema (all fields present on every entry; "" / 0 when N/A):
//   id              — kebab_snake unique identifier (lookups + URL slug)
//   category        — one of NutritionCategory
//   name_en         — English display name
//   name_es         — Spanish display name (populated for Latino category)
//   serving_us      — operator-readable serving (e.g. "4 oz", "1 cup")
//   serving_metric  — metric equivalent (e.g. "113 g", "240 ml")
//   calories
//   protein_g, carbs_g, fiber_g, sugar_g, fat_g
//   saturated_fat_g, cholesterol_mg, sodium_mg, potassium_mg
//   calcium_mg, iron_mg, vitamin_d_iu
//   caffeine_mg     — populated for coffee, energy drinks, sodas, pre-WO
//   notes           — coaching context (effectiveness flags for supps,
//                     sodium watch-outs, etc.)
//   source          — citation
//
// Used by:
//   - Gunny system prompt (id-match → component reconstruct → estimate
//     fallback). See src/lib/foodDbContext.ts for the prompt block.
//   - Nutrition logging UI for autocompletion.
//
// To add an entry: keep fields in this exact order, supply real
// citations, and bump the entry count comment at the top of each
// category section.

export type NutritionCategory =
  | 'proteins'
  | 'grains'
  | 'fruits'
  | 'vegetables'
  | 'dairy'
  | 'fats_nuts_seeds'
  | 'legumes'
  | 'fast_food'
  | 'restaurant_staples'
  | 'latino'
  | 'supplements'
  | 'condiments'
  | 'beverages';

export interface FoodEntry {
  id: string;
  category: NutritionCategory;
  name_en: string;
  name_es: string;
  serving_us: string;
  serving_metric: string;
  calories: number;
  protein_g: number;
  carbs_g: number;
  fiber_g: number;
  sugar_g: number;
  fat_g: number;
  saturated_fat_g: number;
  cholesterol_mg: number;
  sodium_mg: number;
  potassium_mg: number;
  calcium_mg: number;
  iron_mg: number;
  vitamin_d_iu: number;
  caffeine_mg: number;
  notes: string;
  source: string;
}

